import os
import sys

# -------- STEP 1 : GET --------
def scan_get(argv):
    if len(argv) > 1:
        return argv[1]
    return "/Users/nathalie/Dropbox/____BIG_BOFF___/PROJETS/PRO/EURKAI/RESOURCES/FUNCTIONS"

# -------- STEP 2 : EXECUTE (SCAN) --------
def scan_execute(directory):
    collected = []
    for root, dirs, files in os.walk(directory):
        for f in files:
            collected.append(os.path.join(root, f))
    return {"directory": directory, "files": collected}

# -------- STEP 3 : VALIDATE --------
def scan_validate(result):
    if not isinstance(result, dict):
        return {"status": "error", "message": "Result is not a dict"}
    if "files" not in result:
        return {"status": "error", "message": "Missing 'files' in result"}
    return {"status": "ok"}

# -------- STEP 4 : RENDER --------
def scan_render(result, validation):
    return {
        "scan": result,
        "validation": validation
    }

# -------- MASTER METHOD --------
def scan(argv=None):
    if argv is None:
        argv = sys.argv
    directory = scan_get(argv)
    result = scan_execute(directory)
    validation = scan_validate(result)
    return scan_render(result, validation)

if __name__ == "__main__":
    out = scan()
    print(out)
EOF


