import os
import sys

# -------- STEP 1 : GET --------
def scan_get(argv):
    if len(argv) > 1:
        return argv[1]
    return "/Users/nathalie/Dropbox/____BIG_BOFF___/PROJETS/PRO/_INPUTS/EURKAI"

# -------- STEP 2 : EXECUTE (SCAN JSON) --------
def scan_execute(target):
    json_files = []
    if os.path.isfile(target):
        if target.lower().endswith(".json"):
            json_files.append(target)
        return {"target": target, "json_files": json_files}

    for root, dirs, files in os.walk(target):
        for f in files:
            if f.lower().endswith(".json"):
                json_files.append(os.path.join(root, f))

    return {"target": target, "json_files": json_files}

# -------- STEP 3 : VALIDATE --------
def scan_validate(result):
    if "json_files" not in result:
        return {"status": "error", "message": "Missing json_files in result"}
    return {"status": "ok"}

# -------- STEP 4 : RENDER --------
def scan_render(result, validation):
    return {
        "scan": result,
        "validation": validation
    }

# -------- MASTER METHOD --------
def scan(argv=None):
    if argv is None:
        argv = sys.argv
    target = scan_get(argv)
    result = scan_execute(target)
    validation = scan_validate(result)
    return scan_render(result, validation)

if __name__ == "__main__":
    out = scan()
    print(out)
EOF


